#!/usr/bin/env node
/**
 * Phase-2 de-confound — LIGHT bilateral-role-play drama generator.
 *
 * Drives the REAL multi-agent ego/superego architecture (tutor ego→superego→ego,
 * learner ego→superego→ego) over runInteraction — the harness-free path:
 * NO DB, NO scoring, NO rubrics. Each drama in config/poetics-calibration/
 * phase2-dramas-v2.yaml is generated by faithful role-play (NOT one model
 * scripting a "drama"), then neutralized and emitted as a TUTOR:/LEARNER:
 * transcript for the SAME codex instrument + human labeller that ran Phase 2.
 *
 * Why this exists: the Phase-2 gate FAILED (κ=0.044) on a sample with three
 * validity threats (PHASE2-FINDINGS.md §3). This produces a VARIED, de-confounded
 * set so we can re-ask, as a DIAGNOSTIC (n=6, κ is noise — NOT a gate-powered
 * re-run), whether the failure is the instrument's or the sample's.
 *
 * Routing: by default every agent call goes to ONE generator — claude-code CLI
 * (Max-plan quota, not metered API) for --generator claude, or codex exec for
 * --generator codex — regardless of each profile's configured model, so the
 * generator and critic are different models (generator≠critic). The claude bridge
 * is lifted from services/adaptiveTutor/realLLM.js:callClaudeCli: the
 * `--system-prompt` flag REPLACES the default system prompt, which suppresses the
 * explanatory output-style "★ Insight" additions that would otherwise leak into
 * generated turns; the child-env unsets ANTHROPIC_API_KEY so the CLI uses the
 * subscription window instead of billing per call. The codex bridge runs at an
 * explicit reasoning tier (CODEX_REASONING_EFFORT, default xhigh) so the setting
 * is recorded by the run, not silently inherited from ~/.codex/config.toml.
 *
 * Mixed authorship: --role-map routes individual dialogue roles to different
 * models in the SAME drama (e.g. a Claude tutor with a codex learner, or a
 * cross-model superego). This deliberately breaks the single-author/critic
 * symmetry — a mixed drama has no clean arms-length automated critic, so lean on
 * the human labeller. Roles: director, tutor_ego, tutor_superego, learner_ego,
 * learner_superego. The ego role is stable; "initial" vs "adjudication" is a
 * stage on the same role, not a separate actor.
 *
 * Blinding (mirrors load-poetics-phase2-sample.js): only EXTERNAL turns and
 * visible STAGE directions are emitted to the sample. Internal ego/superego
 * deliberation is written to a SEPARATE held-out dir and never reaches the critic
 * or labeller — the unit of analysis is the transcript-as-drama, not an agent's
 * interior (the arc's "no concealed-interior signal" rule). The held-out key
 * (discipline / condition / intended-lean / dramatic-shape) joins to scores +
 * labels only AFTER both.
 *
 * Cost posture: these 6 dramas share ONE Max-plan quota window AND feed a
 * between-condition contrast, so they run SEQUENTIALLY (concurrent → N× drain +
 * differential attrition). Each drama is written as soon as it completes and
 * existing outputs are skipped, so a quota-interrupted run resumes by re-running.
 *
 * Usage:
 *   node scripts/generate-pedagogical-dramas.js --dry-run        # plan only, no LLM, no writes
 *   node scripts/generate-pedagogical-dramas.js --mock           # full pipeline, stub LLM, *-mock dirs (free)
 *   node scripts/generate-pedagogical-dramas.js                  # REAL claude-code CLI (attended, paid quota)
 *   node scripts/generate-pedagogical-dramas.js --only D6        # one drama (debug)
 *   node scripts/generate-pedagogical-dramas.js --force          # overwrite existing sample dir
 *
 * Flags: --seed N (T-id shuffle, default 20260520) · --max-turns N (default 6)
 *        --model <alias> (claude CLI --model, default sonnet) · --out-dir / --key
 *        --delib-dir / --transcripts-dir / --writing-pad-dir
 *        --generator claude|codex · --role-map "tutor=codex,learner=claude" (mixed)
 *        --director-revisit-cue (anchor shorthand) · --director-revisit-policy none|anchor|revoice|reconsider|reframe
 *        --director-revisit-anchor latest|opening|misframing-candidate
 * Env:   CODEX_REASONING_EFFORT (default xhigh) · CODEX_MODEL (default: codex config)
 */

import 'dotenv/config';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';
import { spawn } from 'node:child_process';
import { fileURLToPath } from 'node:url';
import { createHash } from 'node:crypto';
import yaml from 'yaml';
import { jsonrepair } from 'jsonrepair';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKTREE_ROOT = path.resolve(__dirname, '..');
const CAL_DIR = path.join(WORKTREE_ROOT, 'config', 'poetics-calibration');
const DRAMAS_SPEC = path.join(CAL_DIR, 'phase2-dramas-v2.yaml');

// ── args ─────────────────────────────────────────────────────────────────────

function parseArgs(argv) {
  const a = {
    seed: 20260520,
    maxTurns: 6,
    model: 'sonnet',
    generator: 'claude',
    spec: null,
    tidStart: 0,
    mock: false,
    dryRun: false,
    force: false,
    reclean: false,
    only: null,
    outDir: null,
    delibDir: null,
    transcriptsDir: null,
    keyPath: null,
    writingPadDir: null,
    roleMap: null,
    directorMode: 'scene',
    directorRevisitPolicy: 'none',
    directorRevisitAnchor: 'latest',
  };
  for (let i = 0; i < argv.length; i++) {
    const t = argv[i];
    if (t === '--mock') a.mock = true;
    else if (t === '--dry-run') a.dryRun = true;
    else if (t === '--force') a.force = true;
    else if (t === '--reclean') a.reclean = true;
    else if (t === '--seed') a.seed = parseInt(argv[++i], 10);
    else if (t === '--max-turns') a.maxTurns = parseInt(argv[++i], 10);
    else if (t === '--model') a.model = argv[++i];
    else if (t === '--generator') a.generator = argv[++i];
    else if (t === '--spec') a.spec = path.resolve(argv[++i]);
    else if (t === '--tid-start') a.tidStart = parseInt(argv[++i], 10);
    else if (t === '--only') a.only = argv[++i];
    else if (t === '--out-dir') a.outDir = path.resolve(argv[++i]);
    else if (t === '--delib-dir') a.delibDir = path.resolve(argv[++i]);
    else if (t === '--transcripts-dir') a.transcriptsDir = path.resolve(argv[++i]);
    else if (t === '--key') a.keyPath = path.resolve(argv[++i]);
    else if (t === '--writing-pad-dir') a.writingPadDir = path.resolve(argv[++i]);
    else if (t === '--role-map') a.roleMap = parseRoleMap(argv[++i]);
    else if (t === '--director-mode') a.directorMode = argv[++i];
    else if (t === '--director-revisit-cue') a.directorRevisitPolicy = 'anchor';
    else if (t === '--director-revisit-policy') a.directorRevisitPolicy = argv[++i];
    else if (t === '--director-revisit-anchor') a.directorRevisitAnchor = argv[++i];
    else throw new Error(`unknown arg: ${t}`);
  }
  if (!Number.isInteger(a.seed)) throw new Error('--seed must be an integer');
  if (!Number.isInteger(a.maxTurns) || a.maxTurns < 1) throw new Error('--max-turns must be a positive integer');
  if (a.generator !== 'claude' && a.generator !== 'codex')
    throw new Error(`--generator must be claude|codex (got ${a.generator})`);
  if (!Number.isInteger(a.tidStart) || a.tidStart < 0) throw new Error('--tid-start must be a non-negative integer');
  if (!['off', 'scene'].includes(a.directorMode)) throw new Error('--director-mode must be off|scene');
  if (!['none', 'anchor', 'revoice', 'reconsider', 'reframe'].includes(a.directorRevisitPolicy))
    throw new Error('--director-revisit-policy must be none|anchor|revoice|reconsider|reframe');
  if (!['latest', 'opening', 'misframing-candidate'].includes(a.directorRevisitAnchor))
    throw new Error('--director-revisit-anchor must be latest|opening|misframing-candidate');
  a.spec = a.spec || DRAMAS_SPEC;
  // Default output locations are GENERATOR-AWARE so the arms never collide:
  //   claude → phase2-sample-v2 (the running Arm-A set); codex → phase2-sample-codex;
  //   a --role-map → phase2-sample-mixed (distinct maps share it — pass --out-dir to
  //   separate them). mock adds a -mock suffix so a wiring smoke never clobbers a
  //   real labelling set.
  const base = a.roleMap ? 'mixed' : a.generator === 'codex' ? 'codex' : 'v2';
  const suffix = a.mock ? '-mock' : '';
  a.outDir = a.outDir || path.join(CAL_DIR, `phase2-sample-${base}${suffix}`);
  a.delibDir = a.delibDir || path.join(CAL_DIR, `phase2-deliberation-${base}${suffix}`);
  a.transcriptsDir = a.transcriptsDir || path.join(CAL_DIR, `phase2-transcripts-${base}${suffix}`);
  a.keyPath = a.keyPath || path.join(CAL_DIR, `phase2-key-${base}${suffix}.yaml`);
  a.writingPadDir = a.writingPadDir || path.join(a.delibDir, '.writing-pad');
  return a;
}

// ── seeded PRNG (mulberry32) + Fisher–Yates  (lifted from load-poetics) ───────

function mulberry32(seed) {
  let s = seed >>> 0;
  return function () {
    s = (s + 0x6d2b79f5) | 0;
    let t = Math.imul(s ^ (s >>> 15), 1 | s);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function shuffled(arr, rng) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// ── neutralization (identical to load-poetics-phase2-sample.js) ──────────────

const IDENTITY_PATTERNS = [
  [/\b(anthropic|openai|google\s+deepmind|deepmind|openrouter)\b/gi, '[provider]'],
  [/\b(claude|chatgpt|gpt-?\d(?:\.\d)?|gemini(?:\s*flash)?|gemflash|nemotron|llama|mistral)\b/gi, '[model]'],
  [/\b(haiku|sonnet|opus)\b/gi, '[model]'],
  [/\bas an? (?:ai|large )?language model\b/gi, 'as a tutor'],
];

function neutralize(text) {
  let out = text;
  for (const [re, rep] of IDENTITY_PATTERNS) out = out.replace(re, rep);
  return out
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// Recognition-condition tutors sometimes emit a DIRECTOR'S NOTE inside their
// spoken turn — a meta-instruction to their future self that NAMES the intended
// dramatic shape ("Next turn, deploy the population reframe … they may reach for
// it before you offer it"). Left in the transcript it primes the labeller toward
// "recognition": the answer key bleeding into the blind. We strip two signatures:
//   (1) italic-wrapped parentheticals  *( … )*  — the stage-direction typography;
//       in-drama asides to the learner are plain, second-person, inside the quote.
//   (2) a PLAIN parenthetical whose content is director-voiced — third-person
//       "the learner", or planning verbs ("next turn"/"deploy"/"the draft").
// Legit second-person asides ("(say the why first; it's yours to finish)") never
// match cue (2) and are kept. The held-out JSON retains the unstripped text; every
// strip is logged to a sidecar so the heuristic can be audited by eye at small n.
const DIRECTOR_CUES =
  /\b(next turn|the learner\b|deploy\b|the draft|once the learner|they (?:may|might|will|already)|almost as written|the (?:population )?reframe\b|the move\b|this turn,? (?:once|after))\b/i;

function stripStageDirections(text) {
  const removed = [];
  let out = text;
  // (0) ★ Insight blocks: output-style scaffolding that leaks from a spawned
  // claude CLI child (the "explanatory" style rides along even when --system-prompt
  // replaces the system prompt). It speaks in the evaluation architecture's voice
  // ("the revision protects…", "the draft handed the learner…") and must never
  // reach a transcript. Matches the backtick-wrapped "★ Insight ───" opener through
  // the "───" closer.
  out = out.replace(/`?★\s*Insight\s*─+`?[\s\S]*?`?─{5,}`?/g, (m) => {
    removed.push(m);
    return '';
  });
  // (1) italic-wrapped parentheticals: *( ... )*  (may span lines)
  out = out.replace(/\*\(([\s\S]*?)\)\*/g, (m) => {
    removed.push(m);
    return '';
  });
  // (2) plain parenthetical with director voice (3rd-person / planning verbs)
  out = out.replace(/\(([^)]*)\)/g, (m, inner) => {
    if (DIRECTOR_CUES.test(inner)) {
      removed.push(m);
      return '';
    }
    return m;
  });
  out = out
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/[ \t]+\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
  return { text: out, removed };
}

function renderTranscript(turns, removedSink) {
  return (
    turns
      .map((t) => {
        const { text, removed } = stripStageDirections(neutralize(t.text));
        if (removedSink && removed.length) removed.forEach((r) => removedSink.push({ role: t.role, note: r }));
        return `${t.role}: ${text}`;
      })
      .join('\n\n') + '\n'
  );
}

function publicStageDirectionText(text) {
  return String(text || '')
    .trim()
    .replace(/^The director places the tutor\b/i, 'The tutor stands')
    .replace(/^The director places the learner\b/i, 'The learner stands')
    .replace(/^The director (?:sets|opens) (?:the )?scene:?\s*/i, '')
    .replace(/^The director\s+/i, '')
    .replace(/\bscene card\b/gi, 'scene')
    .trim();
}

// A learner turn is "truncated" (generation-time max_tokens clip) if it does not
// end in sentence-final punctuation — a clipped fragment cannot be judged for
// recohering. We don't auto-exclude at n=6; we WARN so the drama can be regenerated.
function isTruncated(text) {
  return !/[.?!…"')\]]$/.test(text.trim());
}

const REVOICE_STOPWORDS = new Set([
  'about',
  'after',
  'again',
  'also',
  'and',
  'are',
  'before',
  'but',
  'can',
  'could',
  'does',
  'for',
  'from',
  'had',
  'has',
  'have',
  'here',
  'how',
  'into',
  'its',
  'just',
  'like',
  'must',
  'not',
  'now',
  'one',
  'out',
  'that',
  'the',
  'then',
  'there',
  'this',
  'too',
  'was',
  'what',
  'when',
  'where',
  'which',
  'while',
  'with',
  'would',
  'you',
  'your',
]);

function revoiceTerms(text) {
  return [
    ...new Set(
      String(text || '')
        .toLowerCase()
        .match(/[a-z0-9]+(?:['’][a-z0-9]+)?/g)
        ?.filter((term) => (term.length > 2 || /\d/.test(term)) && !REVOICE_STOPWORDS.has(term)) || [],
    ),
  ];
}

function extractRevisitAnchor(text) {
  return (
    String(text || '').match(
      /A prior learner line is played back:\s*"([\s\S]*?)"\s*The learner must/i,
    )?.[1] || ''
  );
}

function revoiceMatchStats(anchor, learnerText) {
  const anchorTerms = revoiceTerms(anchor);
  const normalizedLearner = String(learnerText || '').replace(/\s+/g, ' ').trim();
  const learnerOpening =
    normalizedLearner.match(/^.*?[.!?](?=\s|$)/)?.[0] || normalizedLearner.slice(0, 220);
  const learnerTerms = new Set(revoiceTerms(learnerOpening));
  const sharedTerms = anchorTerms.filter((term) => learnerTerms.has(term));
  const overlapRatio = anchorTerms.length ? sharedTerms.length / anchorTerms.length : 0;
  const minimumSharedTerms = Math.min(3, anchorTerms.length);
  return {
    anchor_terms: anchorTerms.length,
    learner_opening_terms: learnerTerms.size,
    shared_terms: sharedTerms.length,
    overlap_ratio: Number(overlapRatio.toFixed(3)),
    compliant: minimumSharedTerms > 0 && sharedTerms.length >= minimumSharedTerms && overlapRatio >= 0.2,
  };
}

function revoiceComplianceFailures(turns) {
  const failures = [];
  for (let i = 0; i < turns.length; i++) {
    const cue = turns[i];
    if (
      cue.role !== 'STAGE' ||
      !/The learner must revoice that wording first/i.test(cue.text) ||
      /name the earlier framing problem/i.test(cue.text)
    ) {
      continue;
    }
    const anchor = extractRevisitAnchor(cue.text);
    const learner = turns.slice(i + 1).find((turn) => turn.role !== 'STAGE');
    const stats = revoiceMatchStats(anchor, learner?.role === 'LEARNER' ? learner.text : '');
    if (anchor && learner?.role === 'LEARNER' && stats.compliant) continue;
    failures.push({
      stage_turn_number: cue.turnNumber ?? i + 1,
      learner_turn_number: learner?.turnNumber ?? null,
      reason: !anchor ? 'missing_anchor' : learner?.role !== 'LEARNER' ? 'missing_followup_learner' : 'low_anchor_overlap',
      ...stats,
    });
  }
  return failures;
}

function namesEarlierFramingProblem(text) {
  const learnerText = String(text || '');
  const explicitProblem =
    /\b(?:framing|frame|reading|read|assumption|assumed|treat(?:ed|ing))\b[\s\S]{0,80}\b(?:problem|trouble|issue|mistake|trap|miss(?:es|ed)?|wrong|off|too\s+\w+|premature|skips?|flattens?|erases?)\b/i;
  const explicitReverse =
    /\b(?:problem|trouble|issue|mistake|trap|miss(?:es|ed)?|wrong|off|too\s+\w+|premature|skips?|flattens?|erases?)\b[\s\S]{0,80}\b(?:framing|frame|reading|read|assumption|assumed|treat(?:ed|ing))\b/i;
  const selfCorrection =
    /\b(?:I|that)\s+(?:jumped|rushed|mistook|reduced|flattened|skipped)\b[\s\S]{0,80}\b(?:before|into|to|the)\b/i;
  const earlierFramingCorrection =
    /\b(?:earlier|old|first)\s+(?:framing|frame|reading)\b[\s\S]{0,100}\b(?:made it sound|sounded|treated|put|reduced|jumped|mistook|too)\b/i;
  const ordinarySelfCorrection = [
    /\b(?:that|it)\s+(?:was|put|made)\b[\s\S]{0,90}\b(?:too\s+\w+|mood first|sound like|ahead|early)\b/i,
    /\bI\s+(?:was still|kept|went straight|made|put)\b[\s\S]{0,90}\b(?:sound like|too\s+\w+|mood first|before|ahead|again)\b/i,
  ].some((pattern) => pattern.test(learnerText));
  return (
    explicitProblem.test(learnerText) ||
    explicitReverse.test(learnerText) ||
    selfCorrection.test(learnerText) ||
    earlierFramingCorrection.test(learnerText) ||
    ordinarySelfCorrection
  );
}

function replacesEarlierFraming(text) {
  const learnerText = String(text || '');
  return [
    /\b(?:instead|rather|now)\b[\s\S]{0,100}\b(?:frame|read|say|put|treat|write|claim)\b/i,
    /\b(?:frame|read|say|put|treat|write|claim)\b[\s\S]{0,80}\b(?:instead|rather|now)\b/i,
    /\b(?:new|better|revised|replacement)\s+(?:frame|framing|reading)\b/i,
    /\bI\s+(?:would|should|need to|can)\s+(?:frame|read|say|put|treat|write|claim)\b/i,
    /\b(?:line|claim|proof|equation|step)\s+(?:now\s+)?(?:is|starts?|reads?|works?|shows?|means?|puts?|becomes?)\b/i,
    /\b(?:image|word)\s+(?:now\s+)?(?:starts?|reads?|works?|shows?|means?|puts?|becomes?)\b/i,
    /\b(?:it|that|this)\s+(?:now\s+)?(?:means?|reads?|becomes?)\b/i,
    /\b(?:more like|better as|read from|looking back)\b/i,
  ].some((pattern) => pattern.test(learnerText));
}

function reframeMatchStats(anchor, learnerText) {
  const revoice = revoiceMatchStats(anchor, learnerText);
  const problemNamed = namesEarlierFramingProblem(learnerText);
  const replacementNamed = replacesEarlierFraming(learnerText);
  return {
    ...revoice,
    revoice_compliant: revoice.compliant,
    problem_named: problemNamed,
    replacement_named: replacementNamed,
    compliant: revoice.compliant && problemNamed && replacementNamed,
  };
}

function reframeComplianceFailures(turns) {
  const failures = [];
  for (let i = 0; i < turns.length; i++) {
    const cue = turns[i];
    if (
      cue.role !== 'STAGE' ||
      !/The learner must revoice that wording first,\s*name the earlier framing problem/i.test(cue.text)
    ) {
      continue;
    }
    const anchor = extractRevisitAnchor(cue.text);
    const learner = turns.slice(i + 1).find((turn) => turn.role !== 'STAGE');
    const stats = reframeMatchStats(anchor, learner?.role === 'LEARNER' ? learner.text : '');
    if (anchor && learner?.role === 'LEARNER' && stats.compliant) continue;
    const missing = [];
    if (!stats.revoice_compliant) missing.push('revoice');
    if (!stats.problem_named) missing.push('framing_problem');
    if (!stats.replacement_named) missing.push('replacement_framing');
    failures.push({
      stage_turn_number: cue.turnNumber ?? i + 1,
      learner_turn_number: learner?.turnNumber ?? null,
      reason: !anchor
        ? 'missing_anchor'
        : learner?.role !== 'LEARNER'
          ? 'missing_followup_learner'
          : 'missing_reframe_consequence',
      missing,
      ...stats,
    });
  }
  return failures;
}

// External drama only: each trace turn (phase tutor|learner) → ROLE: text, in
// conversational order. internalDeliberation is dropped here (held out separately).
//
// restoreLeakedEgo (reclean only): an early build promoted a superego *verdict*
// addressed to the ego ("APPROVED. Ship it as written…") into the public tutor
// turn. The fixed engine keeps the ego draft whenever the superego's IMPROVED
// block opens with "approved"; this re-derives that same choice offline from the
// held-out trace, reclaiming the correct turn without re-calling any LLM.
function externalTurns(trace, { restoreLeakedEgo = false, includeStageDirections = true } = {}) {
  const out = [];
  const seenOpening = (trace.turns || []).some(
    (t) => t.phase === 'director' && Number(t.turnNumber) === 0 && String(t.externalMessage || '').trim(),
  );
  const pushStage = (text, turnNumber = null) => {
    const stageText = publicStageDirectionText(text);
    if (stageText) out.push({ role: 'STAGE', text: stageText, turnNumber });
  };
  if (includeStageDirections && trace.directorPlan?.scene_opening && !seenOpening) {
    pushStage(trace.directorPlan.scene_opening, 0);
  }
  for (const t of trace.turns || []) {
    if (includeStageDirections && t.phase === 'director' && t.externalMessage && String(t.externalMessage).trim()) {
      pushStage(t.externalMessage, t.turnNumber);
      continue;
    }
    if ((t.phase === 'tutor' || t.phase === 'learner') && t.externalMessage && String(t.externalMessage).trim()) {
      let text = String(t.externalMessage).trim();
      if (restoreLeakedEgo && t.phase === 'tutor' && /^\s*approved\b/i.test(text)) {
        const ego = (t.internalDeliberation || []).find((d) => d.role === 'ego');
        if (ego && String(ego.content).trim()) text = String(ego.content).trim();
      }
      out.push({ role: t.phase === 'tutor' ? 'TUTOR' : 'LEARNER', text, turnNumber: t.turnNumber });
    }
  }
  return out;
}

// One held-out key entry. Single source so the generate path and the resume-skip
// path can never drift (design hypotheses from the spec, counts from the turns).
function hasBlockingQualityWarnings(qualityWarnings = []) {
  return qualityWarnings.some((warning) => warning.severity !== 'info');
}

function keyItemFor(d, nTutor, nLearner, qualityWarnings = []) {
  const blocked = hasBlockingQualityWarnings(qualityWarnings);
  return {
    drama_id: d.id,
    discipline: d.discipline,
    condition: d.condition,
    tutor_profile: d.tutor_profile,
    learner_profile: d.learner_profile,
    persona: d.persona,
    intended_tutor_character: d.intended_tutor_character,
    intended_lean: d.intended_lean,
    dramatic_shape: d.dramatic_shape,
    n_tutor_turns: nTutor,
    n_learner_turns: nLearner,
    director_mode: d._directorMode || null,
    director_revisit_cue: Boolean(d._directorRevisitPolicy && d._directorRevisitPolicy !== 'none'),
    director_revisit_policy: d._directorRevisitPolicy || 'none',
    director_revisit_anchor:
      d._directorRevisitPolicy && d._directorRevisitPolicy !== 'none' ? d._directorRevisitAnchor || 'latest' : null,
    opening_speaker: d._directorPlan?.opening_speaker || null,
    ending_speaker: d._directorPlan?.ending_speaker || null,
    quality_status: blocked ? 'review_before_scoring' : 'ok',
    quality_warnings: qualityWarnings,
  };
}

function qualityWarningsFor({ tid, dramaId, turns, removedNotes = [] }) {
  const warnings = [];
  const internalLeakPattern = /\b(?:Superego|same Ego|the Ego|Director Scene Card|scene card|review process|internal review)\b/i;
  const leakedTurns = turns
    .map((t, idx) => ({ ...t, ordinal: idx + 1 }))
    .filter((t) => internalLeakPattern.test(t.text));
  if (leakedTurns.length) {
    warnings.push({
      code: 'possible_internal_process_leak',
      severity: 'warning',
      count: leakedTurns.length,
      turn_numbers: leakedTurns.map((t) => t.turnNumber ?? t.ordinal),
      recommended_action: 'inspect_full_transcript_and_regenerate_before_scoring',
    });
  }
  const truncatedLearnerTurns = turns
    .map((t, idx) => ({ ...t, ordinal: idx + 1 }))
    .filter((t) => t.role === 'LEARNER' && isTruncated(t.text));
  if (truncatedLearnerTurns.length) {
    warnings.push({
      code: 'possibly_truncated_learner_turn',
      severity: 'warning',
      count: truncatedLearnerTurns.length,
      turn_numbers: truncatedLearnerTurns.map((t) => t.turnNumber ?? t.ordinal),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const nLearner = turns.filter((t) => t.role === 'LEARNER').length;
  if (nLearner < 2) {
    warnings.push({
      code: 'too_few_learner_turns',
      severity: 'warning',
      count: nLearner,
      minimum: 2,
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const revoiceFailures = revoiceComplianceFailures(turns);
  if (revoiceFailures.length) {
    warnings.push({
      code: 'revoice_cue_not_revoiced',
      severity: 'warning',
      count: revoiceFailures.length,
      failures: revoiceFailures,
      turn_numbers: revoiceFailures.map((failure) => failure.learner_turn_number || failure.stage_turn_number),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  const reframeFailures = reframeComplianceFailures(turns);
  if (reframeFailures.length) {
    warnings.push({
      code: 'reframe_cue_not_reframed',
      severity: 'warning',
      count: reframeFailures.length,
      failures: reframeFailures,
      turn_numbers: reframeFailures.map((failure) => failure.learner_turn_number || failure.stage_turn_number),
      recommended_action: 'regenerate_or_exclude_before_scoring',
    });
  }
  if (removedNotes.length) {
    warnings.push({
      code: 'stage_direction_leak_stripped',
      severity: 'info',
      count: removedNotes.length,
      artifact: `${tid}.stripped.json`,
      recommended_action: 'audit_stripped_notes',
    });
  }
  return warnings.map((warning) => ({ ...warning, tid, drama_id: dramaId }));
}

function formatQualityWarning(warning) {
  if (warning.code === 'possibly_truncated_learner_turn') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} possibly-truncated learner turn(s) — regenerate or exclude before scoring`;
  }
  if (warning.code === 'too_few_learner_turns') {
    return `${warning.tid} (${warning.drama_id}): only ${warning.count} learner turn(s) — too short to judge recohering`;
  }
  if (warning.code === 'stage_direction_leak_stripped') {
    return `${warning.tid} (${warning.drama_id}): stripped ${warning.count} stage-direction leak(s) — see held-out ${warning.artifact}`;
  }
  if (warning.code === 'possible_internal_process_leak') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} public turn(s) may leak internal process — inspect/regenerate before scoring`;
  }
  if (warning.code === 'revoice_cue_not_revoiced') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} revoice cue(s) were not visibly revoiced — regenerate or exclude before scoring`;
  }
  if (warning.code === 'reframe_cue_not_reframed') {
    return `${warning.tid} (${warning.drama_id}): ${warning.count} reframe cue(s) did not expose the public reframing consequence — regenerate or exclude before scoring`;
  }
  return `${warning.tid} (${warning.drama_id}): ${warning.code}`;
}

function sha256Short(text) {
  return createHash('sha256')
    .update(String(text || ''))
    .digest('hex')
    .slice(0, 16);
}

function buildCallProvenance({
  agentRole,
  backend,
  cli,
  model,
  reasoningEffort,
  systemPrompt,
  userPrompt,
  latencyMs,
  args,
}) {
  return {
    agentRole,
    backend,
    cli,
    model,
    reasoningEffort: reasoningEffort || null,
    latencyMs,
    promptHashes: {
      system: sha256Short(systemPrompt),
      user: sha256Short(userPrompt),
      combined: sha256Short(`${systemPrompt}\n\n---\n\n${userPrompt}`),
    },
    args,
  };
}

function withUsage(result, { provider, model, provenance }) {
  return {
    content: result.content,
    usage: { inputTokens: 0, outputTokens: 0 },
    provider,
    model,
    latencyMs: result.latencyMs,
    generationId: `drama-${provenance.backend}-${provenance.agentRole}-${provenance.promptHashes.combined}`,
    provenance,
    apiPayload: { provenance },
  };
}

// ── claude-code CLI bridge (lifted from realLLM.js:callClaudeCli) ────────────

const CLAUDE_CLI_TIMEOUT_MS = 360_000;
const CLI_TRACE = process.env.GEN_DRAMAS_CLI_TRACE === '1';

function callClaudeCli(systemPrompt, userPrompt, model, role) {
  const start = Date.now();
  return new Promise((resolve, reject) => {
    // --system-prompt REPLACES the default system prompt → suppresses ambient
    // output-style additions (the "★ Insight" block) that would pollute turns.
    const args = ['-p', '-', '--output-format', 'text', '--system-prompt', systemPrompt];
    if (model) args.push('--model', model);
    const env = { ...process.env };
    delete env.CLAUDE_CODE;
    delete env.CLAUDECODE;
    delete env.ANTHROPIC_API_KEY; // force subscription window, not metered API
    delete env.ANTHROPIC_AUTH_TOKEN;
    const child = spawn('claude', args, { stdio: ['pipe', 'pipe', 'pipe'], env });
    let out = '';
    let err = '';
    const to = setTimeout(() => {
      try {
        child.kill('SIGKILL');
      } catch (_) {
        /* gone */
      }
      reject(new Error(`claude CLI timed out after ${CLAUDE_CLI_TIMEOUT_MS}ms (role=${role}, outBytes=${out.length})`));
    }, CLAUDE_CLI_TIMEOUT_MS);
    child.stdout.on('data', (d) => (out += d));
    child.stderr.on('data', (d) => (err += d));
    child.on('error', (e) => {
      clearTimeout(to);
      reject(e);
    });
    child.on('close', (code) => {
      clearTimeout(to);
      if (code !== 0) {
        reject(new Error(err.trim() || out.trim() || `claude CLI exited ${code} (role=${role})`));
      } else {
        const latencyMs = Date.now() - start;
        if (CLI_TRACE) console.error(`[gen-cli] role=${role} ${latencyMs}ms ${out.length}b`);
        resolve({
          content: out.trim(),
          latencyMs,
          provenance: buildCallProvenance({
            agentRole: role,
            backend: 'claude',
            cli: 'claude',
            model: model || 'default',
            reasoningEffort: null,
            systemPrompt,
            userPrompt,
            latencyMs,
            args: [
              '-p',
              '-',
              '--output-format',
              'text',
              '--system-prompt',
              `<sha256:${sha256Short(systemPrompt)}>`,
              ...(model ? ['--model', model] : []),
            ],
          }),
        });
      }
    });
    child.stdin.write(userPrompt);
    child.stdin.end();
  });
}

// ── codex exec CLI bridge (mirrors score-poetics-calibration.js:callCodex) ───
// codex has NO system channel, so system + user are folded into one stdin prompt.
// It uses codex's stored login — a SEPARATE quota pool from the Max-plan claude
// CLI — so a codex generator never contends with a concurrent claude generator,
// and generator≠critic holds (codex-authored dramas are judged by claude-code).
const CODEX_CLI_TIMEOUT_MS = 360_000;
// Reasoning tier is pinned EXPLICITLY here rather than inherited from
// ~/.codex/config.toml, so a run records its own settings and can't silently
// drift if personal config is edited between runs. `model_reasoning_effort` is
// parsed by codex as TOML, hence the embedded quotes (→ string "xhigh").
// CODEX_MODEL stays null by default: we still avoid hardcoding a model name that
// goes stale (codex picks its configured default), but it's overridable for a
// fully-pinned reproducible run. xhigh is gpt-5.x's top tier.
const CODEX_REASONING_EFFORT = process.env.CODEX_REASONING_EFFORT || 'xhigh';
const CODEX_MODEL = process.env.CODEX_MODEL || null;

function callCodexExec(systemPrompt, userPrompt, role) {
  const start = Date.now();
  return new Promise((resolve, reject) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'gen-codex-'));
    const outFile = path.join(tmpDir, 'out.txt');
    const cleanup = () => {
      try {
        fs.rmSync(tmpDir, { recursive: true, force: true });
      } catch (_) {
        /* gone */
      }
    };
    // -s read-only + --ephemeral + per-call -C tmpDir: codex cannot touch the repo.
    const args = ['exec', '--skip-git-repo-check', '--ephemeral', '-s', 'read-only', '-C', tmpDir, '--color', 'never'];
    if (CODEX_MODEL) args.push('-m', CODEX_MODEL);
    if (CODEX_REASONING_EFFORT) args.push('-c', `model_reasoning_effort="${CODEX_REASONING_EFFORT}"`);
    args.push('-o', outFile, '-');
    const child = spawn('codex', args, { stdio: ['pipe', 'pipe', 'pipe'] });
    let err = '';
    const to = setTimeout(() => {
      try {
        child.kill('SIGKILL');
      } catch (_) {
        /* gone */
      }
      cleanup();
      reject(new Error(`codex CLI timed out after ${CODEX_CLI_TIMEOUT_MS}ms (role=${role})`));
    }, CODEX_CLI_TIMEOUT_MS);
    child.stderr.on('data', (d) => (err += d));
    child.on('error', (e) => {
      clearTimeout(to);
      cleanup();
      reject(e);
    });
    child.on('close', (code) => {
      clearTimeout(to);
      let out = '';
      try {
        out = fs.readFileSync(outFile, 'utf8');
      } catch (_) {
        /* missing */
      }
      cleanup();
      if (code !== 0 && !out.trim()) {
        reject(new Error(err.trim() || `codex CLI exited ${code} (role=${role})`));
      } else {
        const latencyMs = Date.now() - start;
        if (CLI_TRACE) console.error(`[gen-cli] role=${role} (codex) ${latencyMs}ms ${out.length}b`);
        resolve({
          content: out.trim(),
          latencyMs,
          provenance: buildCallProvenance({
            agentRole: role,
            backend: 'codex',
            cli: 'codex exec',
            model: CODEX_MODEL || 'config-default',
            reasoningEffort: CODEX_REASONING_EFFORT || null,
            systemPrompt,
            userPrompt,
            latencyMs,
            args,
          }),
        });
      }
    });
    child.stdin.write(`${systemPrompt}\n\n---\n\n${userPrompt}`);
    child.stdin.end();
  });
}

// runInteraction's llmCall contract: (model, systemPrompt, messages, opts) →
// {content, usage}. We IGNORE the per-profile model and force claude-code.
function makeClaudeLlmCall(modelAlias) {
  return async function claudeLlmCall(_model, systemPrompt, messages, opts = {}) {
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const result = await callClaudeCli(systemPrompt, userPrompt, modelAlias, opts.agentRole || 'gen');
    return withUsage(result, {
      provider: 'claude-code',
      model: `claude/${modelAlias || 'default'}`,
      provenance: result.provenance,
    });
  };
}

// Same contract via codex exec. The per-profile model is ignored; system +
// messages are folded by callCodexExec. By default the whole drama is one model
// (--generator codex), but a --role-map can route individual roles to codex while
// others go to claude (see makeRouterLlmCall).
function makeCodexLlmCall() {
  return async function codexLlmCall(_model, systemPrompt, messages, opts = {}) {
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const result = await callCodexExec(systemPrompt, userPrompt, opts.agentRole || 'gen');
    return withUsage(result, {
      provider: 'codex-cli',
      model: `codex/${CODEX_MODEL || 'config-default'}@${CODEX_REASONING_EFFORT || 'default'}`,
      provenance: result.provenance,
    });
  };
}

// Deterministic stub for --mock: role-appropriate canned text, no cost. Proves
// the externalTurns→neutralize→write pipeline end-to-end without the CLI.
function makeMockLlmCall(backend = 'mock') {
  let n = 0;
  return async function mockLlmCall(_model, systemPrompt, messages, opts = {}) {
    n++;
    const role = opts.agentRole || 'agent';
    const userPrompt = (messages || []).map((m) => m.content).join('\n');
    const latencyMs = 0;
    const result = {
      content: `[mock ${backend}:${role} #${n}] This is a stand-in turn for wiring validation only.`,
      latencyMs,
      provenance: buildCallProvenance({
        agentRole: role,
        backend,
        cli: 'mock',
        model: `mock-${backend}`,
        reasoningEffort: null,
        systemPrompt,
        userPrompt,
        latencyMs,
        args: [],
      }),
    };
    return withUsage(result, {
      provider: `${backend}-mock`,
      model: `mock/${backend}`,
      provenance: result.provenance,
    });
  };
}

// ── per-role model routing ───────────────────────────────────────────────────
// The bilateral engine tags every llmCall with opts.agentRole (one of the five
// strings below). A --role-map lets DIFFERENT roles be authored by DIFFERENT
// models in the SAME drama — e.g. a Claude tutor drawing out a codex learner, or
// a cross-model superego (codex critiquing Claude's drafts). Resolution is
// most-specific-first: exact role > side (tutor|learner) > explicit default >
// the --generator fallback. NOTE: a mixed drama has no single "author", so the
// clean generator≠critic guarantee no longer holds end-to-end — pick the human/
// instrument critic deliberately (see the run's closing note).
const ROLE_ALIASES = {
  learner_ego_initial: 'learner_ego',
  learner_ego_revision: 'learner_ego',
};
const ROLE_NAMES = ['director', 'tutor_ego', 'tutor_superego', 'learner_ego', 'learner_superego'];
const ROLE_MAP_KEYS = new Set(['tutor', 'learner', 'default', ...ROLE_NAMES]);

function parseRoleMap(str) {
  const map = {};
  for (const pair of String(str)
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean)) {
    const eq = pair.indexOf('=');
    if (eq < 1) throw new Error(`--role-map entry must be key=value (got "${pair}")`);
    const rawKey = pair.slice(0, eq).trim();
    const k = ROLE_ALIASES[rawKey] || rawKey;
    const v = pair.slice(eq + 1).trim();
    if (!ROLE_MAP_KEYS.has(k)) throw new Error(`--role-map key "${rawKey}" not one of: ${[...ROLE_MAP_KEYS].join(', ')}`);
    if (v !== 'claude' && v !== 'codex')
      throw new Error(`--role-map value for "${k}" must be claude|codex (got "${v}")`);
    map[k] = v;
  }
  if (Object.keys(map).length === 0) throw new Error('--role-map is empty');
  return map;
}

function resolveBackend(agentRole, roleMap, fallback) {
  if (agentRole && roleMap[agentRole]) return roleMap[agentRole]; // exact role
  const side =
    agentRole && agentRole.startsWith('tutor')
      ? 'tutor'
      : agentRole && agentRole.startsWith('learner')
        ? 'learner'
        : null;
  if (side && roleMap[side]) return roleMap[side]; // tutor|learner side
  if (roleMap.default) return roleMap.default; // explicit default
  return fallback; // --generator
}

// Router llmCall: dispatch each role to its resolved backend. Under --mock both
// backends are the same stub, but the route decision is still computed + logged
// (GEN_DRAMAS_CLI_TRACE=1) so routing can be smoke-tested for free.
function makeRouterLlmCall({ roleMap, fallback, claudeModelAlias, mock }) {
  const claudeBridge = mock ? makeMockLlmCall('claude') : makeClaudeLlmCall(claudeModelAlias);
  const codexBridge = mock ? makeMockLlmCall('codex') : makeCodexLlmCall();
  return async function routerLlmCall(model, systemPrompt, messages, opts = {}) {
    const backend = resolveBackend(opts.agentRole, roleMap, fallback);
    if (CLI_TRACE) console.error(`[gen-route] role=${opts.agentRole || '?'} → ${backend}`);
    const bridge = backend === 'codex' ? codexBridge : claudeBridge;
    return bridge(model, systemPrompt, messages, opts);
  };
}

// ── teaching-drama director ─────────────────────────────────────────────────
// The director is a scene-level author, not a tutor or learner. Its output is
// hidden from the clean public transcript and preserved in the full transcript.
// It varies scene setting, register, speaker order, direct-address budget, and
// scheduled "deus ex machina" cues that the next actor must absorb privately.
const VOICE_VARIANTS = [
  {
    locale: 'international academic English, compact and low idiom',
    register: 'seminar-table reserve; fewer direct second-person appeals',
    person_policy: 'Allow indirect third-person framing; avoid beginning every turn with I/you.',
  },
  {
    locale: 'British/Commonwealth classroom English',
    register: 'dry, clipped, lightly ironic but not sarcastic',
    person_policy: 'Prefer declarative turns and concrete examples over validation-first phrasing.',
  },
  {
    locale: 'workplace training room',
    register: 'adult learner, practical stakes, compressed speech',
    person_policy: 'Use first person only when the speaker is actually owning a claim.',
  },
  {
    locale: 'multilingual learner using plain English',
    register: 'direct, slightly elliptical, non-fluent but not caricatured',
    person_policy: 'Avoid fake dialect spelling; show register through syntax, brevity, and repair.',
  },
  {
    locale: 'rural/community college tutorial',
    register: 'plain-spoken, wary of abstractions, concrete objects first',
    person_policy: 'Limit "you" validation; make speakers point at the thing in the room.',
  },
  {
    locale: 'online asynchronous feedback thread',
    register: 'short posts, delayed replies, occasional quotation of prior text',
    person_policy: 'Allow quoted fragments and third-person reference to submitted work.',
  },
];

const SETTINGS = [
  'after class, with chairs already being stacked',
  'a workplace training session during a short break',
  'a community college tutoring desk with a queue forming nearby',
  'an online course comment thread after a marked exercise',
  'a museum/gallery education session with the object in view',
  'a lab bench conversation while equipment is being packed away',
];

function variantIndex(dramaId, offset = 0) {
  const n = Number(String(dramaId || '').replace(/\D/g, '')) || 0;
  return Math.abs(n + offset) % VOICE_VARIANTS.length;
}

function fallbackDirectorPlan(d, reason = 'fallback') {
  const voice = VOICE_VARIANTS[variantIndex(d.id)];
  const setting = d.scene_setting || SETTINGS[variantIndex(d.id, 2)];
  const opensWithTutor = variantIndex(d.id, 1) % 3 === 0;
  const endsWithTutor = variantIndex(d.id, 2) % 4 === 0;
  return {
    parse_status: reason,
    scene_setting: setting,
    scene_opening: `The scene opens ${setting}; the misconception is already present in the learner's situation, not only in a direct question.`,
    relationship: d.relationship || 'a tutor and learner who do not yet share a stable register',
    stakes: d.stakes || d.learner_start_state || d.topic,
    opening_speaker: d.opening_speaker || (opensWithTutor ? 'tutor' : 'learner'),
    ending_speaker: d.ending_speaker || (endsWithTutor ? 'tutor' : 'learner'),
    locale: d.locale || voice.locale,
    register: d.register || voice.register,
    voice_constraints:
      d.voice_constraints ||
      `${voice.person_policy} Avoid the repeated American tutoring pattern of "I hear you / your intuition is right / what do you think".`,
    person_policy: d.person_policy || voice.person_policy,
    direct_address_budget: d.direct_address_budget || 'No more than one direct "you/your" validation beat per public turn.',
    side_constraints: {
      tutor:
        d.tutor_voice_constraint ||
        'The tutor need not always validate first; sometimes begin with an object, a counterexample, silence, or a concise claim.',
      learner:
        d.learner_voice_constraint ||
        'The learner should not always narrate confusion in polished first person; allow fragments, resistance, overheard reasoning, or practical stakes.',
    },
    interventions: [
      {
        after_turn: 2,
        timing: variantIndex(d.id, 3) % 2 === 0 ? 'before_tutor' : 'before_learner',
        instruction:
          d.director_intervention ||
          'A small external interruption changes the rhythm. The next speaker must answer under time pressure and avoid a tidy explanatory paragraph.',
        reasoning: 'Scheduled director cue to prevent smooth alternation from becoming routine.',
      },
    ],
    director_note:
      d.director_note ||
      'The director varies scene ecology and voice; this is not a hidden label for recognition, flatness, trap, or impasse.',
  };
}

function withDirectorCueProvenance(plan) {
  if (!plan?.provenance || !Array.isArray(plan.interventions)) return plan;
  return {
    ...plan,
    interventions: plan.interventions.map((cue) => ({
      ...cue,
      provenance: cue.provenance || plan.provenance,
    })),
  };
}

function withDirectorRevisitCue(plan, policy, anchorPolicy) {
  if (!plan || !policy || policy === 'none') return plan;
  const cueText =
    policy === 'reframe'
      ? 'A prior learner line is played back. The learner must revoice that earlier wording first, name the earlier framing problem in public speech, then replace it with a new framing that changes how the earlier line reads.'
      : policy === 'reconsider'
        ? 'A prior learner line is played back. The learner must revoice that earlier wording first, then decide in public whether it still stands, needs narrowing, or needs replacing before moving on.'
      : policy === 'revoice'
        ? 'A prior learner line is played back. The learner must revoice that earlier wording before moving on, then say exactly what it now misses, keeps, or changes.'
        : 'A prior learner line is played back or pointed to. The next learner line must repeat or close-paraphrase one earlier phrase they used, then say what that phrase now misses, keeps, or changes.';
  const cueReasoning =
    policy === 'reframe'
      ? 'Opt-in reframe mirror: the learner must expose the earlier line, the framing problem, and the replacement framing in public speech.'
      : policy === 'reconsider'
        ? 'Opt-in reconsideration mirror: the learner must make a public judgment about earlier wording without being forced to replace it.'
      : policy === 'revoice'
        ? 'Opt-in revoice mirror: the learner must make the earlier wording and the change to it legible in public speech.'
        : 'Opt-in rehearsal mirror: the learner must visibly revisit earlier wording instead of only accepting the latest correction.';
  const cue = {
    after_turn: 2,
    timing: 'before_learner',
    instruction: cueText,
    reasoning: cueReasoning,
    provenance: plan.provenance || null,
    cue_kind: 'learner_revisit_earlier_wording',
    revisit_policy: policy,
    revisit_anchor: anchorPolicy || 'latest',
  };
  const interventions = Array.isArray(plan.interventions) ? plan.interventions : [];
  if (interventions.some((entry) => entry.cue_kind === cue.cue_kind)) return plan;
  return {
    ...plan,
    revisit_cue: cue.cue_kind,
    revisit_cue_policy: policy,
    revisit_cue_anchor: cue.revisit_anchor,
    interventions: [...interventions, cue],
  };
}

function extractJsonObject(text) {
  const raw = String(text || '').trim();
  if (!raw) return null;
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i)?.[1];
  const candidate = fenced || raw.slice(raw.indexOf('{'), raw.lastIndexOf('}') + 1);
  if (!candidate || !candidate.trim().startsWith('{')) return null;
  return JSON.parse(jsonrepair(candidate));
}

function buildDirectorSystemPrompt() {
  return `You are the director of a teaching drama. You never tutor and you never play the learner.

Create a hidden scene card that will guide separate tutor and learner agents. Your job is to break routine: vary setting, relation, voice, speaker order, and occasional external intervention while preserving the learning topic.

Do not stereotype dialect, nationality, class, or region. Locale/register constraints should affect rhythm, idiom density, directness, and situation, not caricatured spelling.
Write visible stage directions as play text. Do not start them with "The director..." and do not explain your intention inside them.

Return exactly one JSON object with:
{
  "scene_setting": "where/when the teaching scene happens",
  "scene_opening": "one sentence stage opening",
  "relationship": "social relation between tutor and learner",
  "stakes": "why this matters in the scene",
  "opening_speaker": "learner|tutor|director",
  "ending_speaker": "learner|tutor|director",
  "locale": "English/register ecology",
  "register": "speech style and affective temperature",
  "voice_constraints": "constraints that prevent generic American AI tutoring prose",
  "person_policy": "how much first/second/third person is allowed",
  "direct_address_budget": "budget for direct you/your validation",
  "side_constraints": {"tutor": "...", "learner": "..."},
  "interventions": [{"after_turn": 2, "timing": "before_tutor|before_learner", "instruction": "...", "reasoning": "..."}],
  "director_note": "why this scene ecology was chosen"
}`;
}

async function buildDirectorPlan(d, llmCall, args) {
  if (args.directorMode === 'off') return null;
  const fallback = fallbackDirectorPlan(d, 'fallback-not-called');
  const userPrompt = yaml.stringify({
    drama_id: d.id,
    discipline: d.discipline,
    topic: d.topic,
    condition: d.condition,
    scenario_name: d.scenario_name,
    learner_start_state: d.learner_start_state,
    persona: d.persona,
    intended_tutor_character: d.intended_tutor_character,
    forbidden_failure_modes: [
      'every turn in first/second person',
      'standard American AI tutor voice',
      'learner always starts and always has the last word',
      'scenario only begins in medias res as a direct learner question',
      'superego drafts public speech',
    ],
    opt_in_revisit_cue:
      args.directorRevisitPolicy !== 'none' &&
      `The generator will inject one visible learner look-back cue after turn 2 using the ${args.directorRevisitPolicy} policy and the ${args.directorRevisitAnchor} anchor selector. Let the scene make that cue plausible without naming recognition or guaranteeing a breakthrough.`,
    fallback_variation_seed: fallback,
  });
  const response = await llmCall(
    'director',
    buildDirectorSystemPrompt(),
    [{ role: 'user', content: userPrompt }],
    {
      temperature: 0.85,
      maxTokens: 900,
      agentRole: 'director',
    },
  );
  try {
    const parsed = extractJsonObject(response.content);
    if (!parsed) throw new Error('no JSON object');
    return withDirectorCueProvenance(
      withDirectorRevisitCue(
        {
          ...fallback,
          ...parsed,
          interventions:
            Array.isArray(parsed.interventions) && parsed.interventions.length ? parsed.interventions : fallback.interventions,
          parse_status: 'ok',
          provenance: response.provenance || response.apiPayload?.provenance || null,
        },
        args.directorRevisitPolicy,
        args.directorRevisitAnchor,
      ),
    );
  } catch (error) {
    return withDirectorCueProvenance(
      withDirectorRevisitCue(
        {
          ...fallbackDirectorPlan(d, `fallback-parse-failed:${error.message}`),
          raw_director_response: String(response.content || '').slice(0, 2000),
          provenance: response.provenance || response.apiPayload?.provenance || null,
        },
        args.directorRevisitPolicy,
        args.directorRevisitAnchor,
      ),
    );
  }
}

// --reclean: re-derive the EXTERNAL .txt transcripts from the held-out trace JSON,
// applying the CURRENT stage-direction strip — without re-calling any LLM. Lets a
// run that already landed (under an older renderTranscript) be re-cleaned in place,
// and prints every stripped note so the heuristic can be audited by eye at small n.
function reclean(args) {
  if (!fs.existsSync(args.delibDir)) throw new Error(`no held-out dir to reclean from: ${args.delibDir}`);
  const jsons = fs
    .readdirSync(args.delibDir)
    .filter((f) => /^T\d+\.json$/.test(f))
    .sort();
  if (!jsons.length) throw new Error(`no held-out T*.json in ${args.delibDir}`);
  fs.mkdirSync(args.outDir, { recursive: true });
  console.log('\n══ reclean — re-deriving .txt from held-out trace (no LLM) ══');
  console.log(`  from: ${path.relative(WORKTREE_ROOT, args.delibDir)}`);
  console.log(`  to:   ${path.relative(WORKTREE_ROOT, args.outDir)}`);
  let total = 0;
  for (const f of jsons) {
    const tid = f.replace(/\.json$/, '');
    const trace = JSON.parse(fs.readFileSync(path.join(args.delibDir, f), 'utf8'));
    const turns = externalTurns(trace, { restoreLeakedEgo: true });
    const removed = [];
    const publicTranscript = renderTranscript(turns, removed);
    fs.writeFileSync(path.join(args.outDir, `${tid}.txt`), publicTranscript, 'utf8');
    writeHeldOutTranscripts({
      args,
      tid,
      dramaId: trace.drama_id || trace.dramaId || 'unknown',
      trace,
      publicTranscript,
    });
    if (removed.length) {
      total += removed.length;
      fs.writeFileSync(path.join(args.delibDir, `${tid}.stripped.json`), JSON.stringify(removed, null, 2), 'utf8');
      console.log(`  ${tid}: stripped ${removed.length}`);
      for (const r of removed) console.log(`      [${r.role}] ${r.note.replace(/\s+/g, ' ').slice(0, 140)}`);
    } else {
      console.log(`  ${tid}: clean`);
    }
  }
  console.log(`\nre-cleaned ${jsons.length} transcript(s) · ${total} stage-direction note(s) stripped`);
}

function formatStageSuffix(stage) {
  if (!stage) return '';
  if (stage === 'initial') return ' (initial suggestion)';
  if (stage === 'adjudication') return ' (adjudication/final authority)';
  if (stage === 'critique') return ' (critique)';
  return ` (${stage})`;
}

function formatRoleLabel(phase, role, stage = null) {
  if (phase === 'director' || role === 'director') return `Director${formatStageSuffix(stage)}`;
  if (phase === 'tutor') {
    if (role === 'ego') return `Tutor Ego${formatStageSuffix(stage)}`;
    if (role === 'superego') return `Tutor Superego${formatStageSuffix(stage)}`;
    return `Tutor ${role}${formatStageSuffix(stage)}`;
  }
  if (role === 'ego' || role === 'ego_initial' || role === 'ego_revision') return `Learner Ego${formatStageSuffix(stage)}`;
  if (role === 'superego') return `Learner Superego${formatStageSuffix(stage)}`;
  if (role === 'unified_learner') return 'Learner';
  return `Learner ${role}${formatStageSuffix(stage)}`;
}

function formatProvenance(entry) {
  const p = entry?.apiPayload?.provenance || {};
  const m = entry?.metrics || {};
  const latency = p.latencyMs ?? m.latencyMs;
  const parts = [
    `role=${p.agentRole || entry?.role || 'unknown'}`,
    `backend=${p.backend || m.provider || 'unknown'}`,
    `model=${p.model || m.model || 'unknown'}`,
  ];
  if (p.reasoningEffort) parts.push(`reasoning=${p.reasoningEffort}`);
  if (p.promptHashes?.combined) parts.push(`prompt=${p.promptHashes.combined}`);
  if (latency != null) parts.push(`latencyMs=${latency}`);
  return parts.join(' | ');
}

function formatHeldOutEntryContent(entry) {
  const raw = String(entry?.content || '').trim();
  if (!raw || entry?.stage !== 'adjudication') return raw;

  const finalMatch = raw.match(/\bFINAL:\s*([\s\S]*)/i);
  if (!finalMatch?.[1]?.trim()) return raw;

  const decisionMatch = raw.match(/\b(?:PRIVATE_)?DECISION:\s*([^\n]*)/i);
  const lines = [];
  if (decisionMatch?.[1]?.trim()) {
    lines.push(`_private decision: ${decisionMatch[1].trim()}_`, '');
  }
  lines.push('**Final public speech:**', '', finalMatch[1].trim());
  return lines.join('\n');
}

function renderHeldOutTranscript(trace, { tid, dramaId, mode }) {
  const includeTurn = (turn) => mode === 'full' || mode === 'stage' || turn.phase === mode;
  const title =
    mode === 'full'
      ? 'Full held-out role transcript'
      : mode === 'stage'
        ? 'Stage transcript'
      : mode === 'tutor'
        ? 'Tutor held-out role transcript'
        : 'Learner held-out role transcript';
  const lines = [`# ${title}`, '', `tid: ${tid}`, `drama_id: ${dramaId}`, ''];

  if ((mode === 'full' || mode === 'stage') && trace.directorPlan) {
    lines.push('## Director Scene Card', '');
    lines.push('```yaml');
    lines.push(yaml.stringify(trace.directorPlan).trim());
    lines.push('```', '');
  }

  for (const turn of trace.turns || []) {
    if (!includeTurn(turn)) continue;
    lines.push(`## Turn ${turn.turnNumber} / ${turn.phase.toUpperCase()}`, '');
    for (const entry of turn.internalDeliberation || []) {
      lines.push(`### ${formatRoleLabel(turn.phase, entry.role, entry.stage)}`);
      lines.push(`_provenance: ${formatProvenance(entry)}_`, '');
      lines.push(formatHeldOutEntryContent(entry) || '(empty)');
      lines.push('');
    }
    if (turn.phase === 'tutor' || turn.phase === 'learner') {
      lines.push(`### ${turn.phase === 'tutor' ? 'Tutor Public Output' : 'Learner Public Output'}`);
      lines.push(String(turn.externalMessage || '').trim() || '(empty)');
      lines.push('');
    } else if (turn.phase === 'director') {
      lines.push('### Director Cue');
      lines.push(String(turn.externalMessage || '').trim() || '(empty)');
      lines.push('');
    }
  }

  return (
    lines
      .join('\n')
      .replace(/\n{4,}/g, '\n\n\n')
      .trim() + '\n'
  );
}

function writeHeldOutTranscripts({ args, tid, dramaId, trace, publicTranscript }) {
  fs.mkdirSync(args.transcriptsDir, { recursive: true });
  const artifacts = {
    public: path.join(args.transcriptsDir, `${tid}.public.txt`),
    full: path.join(args.transcriptsDir, `${tid}.full.md`),
    stage: path.join(args.transcriptsDir, `${tid}.stage.md`),
    tutor: path.join(args.transcriptsDir, `${tid}.tutor.md`),
    learner: path.join(args.transcriptsDir, `${tid}.learner.md`),
  };
  fs.writeFileSync(artifacts.public, publicTranscript, 'utf8');
  fs.writeFileSync(artifacts.full, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'full' }), 'utf8');
  fs.writeFileSync(artifacts.stage, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'stage' }), 'utf8');
  fs.writeFileSync(artifacts.tutor, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'tutor' }), 'utf8');
  fs.writeFileSync(artifacts.learner, renderHeldOutTranscript(trace, { tid, dramaId, mode: 'learner' }), 'utf8');
  return Object.fromEntries(Object.entries(artifacts).map(([k, v]) => [k, path.relative(WORKTREE_ROOT, v)]));
}

function prepareWritingPad(args) {
  fs.mkdirSync(args.writingPadDir, { recursive: true });
  process.env.EVAL_WRITING_PAD_DIR = args.writingPadDir;
  return {
    mode: 'isolated',
    dir: path.relative(WORKTREE_ROOT, args.writingPadDir),
  };
}

async function loadInteractionRuntime(args) {
  const writingPad = prepareWritingPad(args);
  const [{ runInteraction }, learnerWritingPad, tutorWritingPad] = await Promise.all([
    import('../services/learnerTutorInteractionEngine.js'),
    import('../services/memory/learnerWritingPad.js'),
    import('../services/memory/tutorWritingPad.js'),
  ]);
  if (!learnerWritingPad.isAvailable() || !tutorWritingPad.isAvailable()) {
    throw new Error(
      `Writing Pad unavailable after initialization (dir=${writingPad.dir}). ` +
        'Refusing to run drama generation without explicit tutor/learner memory.',
    );
  }
  return {
    runInteraction,
    writingPad: {
      ...writingPad,
      learnerDb: path.relative(WORKTREE_ROOT, learnerWritingPad.getStoragePath()),
      tutorDb: path.relative(WORKTREE_ROOT, tutorWritingPad.getStoragePath()),
    },
  };
}

// ── main ─────────────────────────────────────────────────────────────────────

async function main() {
  const args = parseArgs(process.argv.slice(2));
  if (args.reclean) return reclean(args);
  if (!fs.existsSync(args.spec)) throw new Error(`dramas spec not found: ${args.spec}`);
  const spec = yaml.parse(fs.readFileSync(args.spec, 'utf8'));
  const dramas = spec.dramas || [];
  if (dramas.length === 0) throw new Error('no dramas in spec');

  // Seeded T-id assignment over the FULL spec FIRST, so the neutral id encodes
  // neither condition nor spec order. --tid-start offsets the numbering so a
  // SECOND spec can APPEND into the same dir (T07-T18 alongside T01-T06) without
  // the Fisher–Yates shuffle remapping the already-landed ids — the shuffle is
  // NOT stable under a set-size change.
  const rng = mulberry32(args.seed);
  let order = shuffled(dramas, rng);
  const width = Math.max(2, String(args.tidStart + order.length).length);
  order.forEach((d, i) => (d._tid = `T${String(i + 1 + args.tidStart).padStart(width, '0')}`));

  // --only filters AFTER T-id assignment so targeted regeneration preserves the
  // full-set alignment (filtering BEFORE the shuffle would misassign every id).
  // Accepts a comma-list of drama-ids (D7) and/or T-ids (T06).
  if (args.only) {
    const want = new Set(
      String(args.only)
        .split(',')
        .map((s) => s.trim())
        .filter(Boolean),
    );
    order = order.filter((d) => want.has(d.id) || want.has(d._tid));
    if (order.length === 0) throw new Error(`--only matched no dramas: ${args.only}`);
  }

  const roleMapLabel = args.roleMap
    ? Object.entries(args.roleMap)
        .map(([k, v]) => `${k}→${v}`)
        .join(', ')
    : null;
  const genLabel = args.mock
    ? args.roleMap
      ? `MOCK (routed: ${roleMapLabel})`
      : 'MOCK'
    : args.roleMap
      ? `REAL (mixed: ${roleMapLabel}; fallback=${args.generator})`
      : args.generator === 'codex'
        ? 'REAL (codex exec)'
        : `REAL (claude --model ${args.model})`;
  console.log(`\n══ Phase-2 de-confound generator — ${genLabel} ══`);
  console.log(
    `  generator: ${args.roleMap ? 'mixed' : args.generator} · dramas: ${order.length} · maxTurns: ${args.maxTurns} · ` +
      `seed: ${args.seed}${args.tidStart ? ` · tid-start: ${args.tidStart}` : ''} · director: ${args.directorMode}` +
      `${args.directorRevisitPolicy !== 'none' ? ` + revisit-${args.directorRevisitPolicy}/${args.directorRevisitAnchor}` : ''}`,
  );
  console.log(`  out: ${path.relative(WORKTREE_ROOT, args.outDir)}`);
  console.log(`  held-out transcripts: ${path.relative(WORKTREE_ROOT, args.transcriptsDir)}`);
  for (const d of order) {
    console.log(
      `  ${d._tid} ← ${d.id}  [${d.condition}]  ${d.discipline} · persona=${d.persona} · ` +
        `tutor=${d.tutor_profile} · learner=${d.learner_profile}`,
    );
  }

  if (args.dryRun) {
    console.log('\n── DRY RUN — nothing written, no LLM called. Plan + shuffle above. ──');
    return;
  }

  if (
    fs.existsSync(args.outDir) &&
    fs.readdirSync(args.outDir).some((f) => f.endsWith('.txt')) &&
    !args.force &&
    !args.only &&
    args.tidStart === 0
  ) {
    // Resume: existing .txt are skipped (and keyed from their trace below); only
    // missing dramas are generated. Per-drama skip guards against clobber, so this
    // is safe to proceed — use --force to regenerate all, --only to target a subset.
    console.log(`\n── resume: ${args.outDir} already has transcripts; generating only the missing dramas ──`);
  }
  fs.mkdirSync(args.outDir, { recursive: true });
  fs.mkdirSync(args.delibDir, { recursive: true });
  fs.mkdirSync(args.transcriptsDir, { recursive: true });

  const runtime = await loadInteractionRuntime(args);

  const llmCall = args.roleMap
    ? makeRouterLlmCall({
        roleMap: args.roleMap,
        fallback: args.generator,
        claudeModelAlias: args.model,
        mock: args.mock,
      })
    : args.mock
      ? makeMockLlmCall(args.generator)
      : args.generator === 'codex'
        ? makeCodexLlmCall()
        : makeClaudeLlmCall(args.model);
  const keyItems = {};
  const warnings = [];

  // SEQUENTIAL by design (shared quota window + between-condition contrast).
  for (const d of order) {
    const outTxt = path.join(args.outDir, `${d._tid}.txt`);
    // --only means "regenerate exactly these", so it always overwrites its
    // selection; bare resume skips anything already on disk.
    if (fs.existsSync(outTxt) && !args.force && !args.only) {
      // Resume: don't regenerate, but still record this drama in the held-out key
      // from its existing trace, so a partial/append run emits a COMPLETE key
      // (otherwise skipped dramas survive only if a prior key happened to exist).
      const tracePath = path.join(args.delibDir, `${d._tid}.json`);
      if (fs.existsSync(tracePath)) {
        try {
          const traceJson = JSON.parse(fs.readFileSync(tracePath, 'utf8'));
          const t = externalTurns(traceJson, { restoreLeakedEgo: true });
          writeHeldOutTranscripts({
            args,
            tid: d._tid,
            dramaId: d.id,
            trace: traceJson,
            publicTranscript: renderTranscript(t),
          });
          keyItems[d._tid] = keyItemFor(
            {
              ...d,
              _directorMode: traceJson.run?.director_mode || null,
              _directorRevisitPolicy:
                traceJson.run?.director_revisit_policy ||
                (traceJson.run?.director_revisit_cue ? 'anchor' : 'none'),
              _directorRevisitAnchor: traceJson.run?.director_revisit_anchor || 'latest',
              _directorPlan: traceJson.directorPlan || null,
            },
            t.filter((x) => x.role === 'TUTOR').length,
            t.filter((x) => x.role === 'LEARNER').length,
            traceJson.quality_warnings || qualityWarningsFor({ tid: d._tid, dramaId: d.id, turns: t }),
          );
        } catch (_) {
          /* fall back to prior-key merge */
        }
      }
      console.log(`\n  ${d._tid} (${d.id}) — exists, skipping (resume; keyed from trace). Use --force to regenerate.`);
      continue;
    }
    console.log(`\n  ${d._tid} (${d.id}) — generating ${d.discipline}/${d.condition} …`);
    const t0 = Date.now();
    const directorPlan = await buildDirectorPlan(d, llmCall, args);
    d._directorMode = args.directorMode;
    d._directorRevisitPolicy = args.directorRevisitPolicy;
    d._directorRevisitAnchor = args.directorRevisitAnchor;
    d._directorPlan = directorPlan;
    if (directorPlan) {
      console.log(
        `    director → opens=${directorPlan.opening_speaker} ends=${directorPlan.ending_speaker || 'unspecified'} ` +
          `register=${String(directorPlan.register || directorPlan.locale || 'n/a').slice(0, 80)}`,
      );
    }
    const trace = await runtime.runInteraction(
      {
        learnerId: `drama-${d.id}-${Date.now()}`,
        personaId: d.persona,
        tutorProfile: d.tutor_profile,
        topic: d.topic,
        scenario: { name: d.scenario_name, learnerStartState: d.learner_start_state, directorPlan },
        sessionId: `drama-${d.id}-${Date.now()}`,
      },
      llmCall,
      {
        maxTurns: args.maxTurns,
        observeInternals: true,
        learnerProfile: d.learner_profile,
        forceMaxTurns: true,
        directorPlan,
      },
    );

    const turns = externalTurns(trace);
    const nTutor = turns.filter((t) => t.role === 'TUTOR').length;
    const nLearner = turns.filter((t) => t.role === 'LEARNER').length;

    const removedNotes = [];
    const publicTranscript = renderTranscript(turns, removedNotes);
    fs.writeFileSync(outTxt, publicTranscript, 'utf8');
    const qualityWarnings = qualityWarningsFor({ tid: d._tid, dramaId: d.id, turns, removedNotes });
    warnings.push(...qualityWarnings.map(formatQualityWarning));
    if (removedNotes.length) {
      fs.writeFileSync(
        path.join(args.delibDir, `${d._tid}.stripped.json`),
        JSON.stringify(removedNotes, null, 2),
        'utf8',
      );
    }
    const transcriptArtifacts = writeHeldOutTranscripts({
      args,
      tid: d._tid,
      dramaId: d.id,
      trace,
      publicTranscript,
    });
    // HELD OUT — full trace incl. internal deliberation; never shown to critic/labeller.
    fs.writeFileSync(
      path.join(args.delibDir, `${d._tid}.json`),
      JSON.stringify(
        {
          tid: d._tid,
          drama_id: d.id,
          run: {
            generator: args.roleMap ? 'mixed' : args.generator,
            role_map: args.roleMap || null,
            director_mode: args.directorMode,
            director_revisit_cue: args.directorRevisitPolicy !== 'none',
            director_revisit_policy: args.directorRevisitPolicy,
            director_revisit_anchor: args.directorRevisitPolicy !== 'none' ? args.directorRevisitAnchor : null,
            model: args.generator === 'codex' ? `codex@${CODEX_REASONING_EFFORT}` : args.model,
            codex_reasoning_effort: CODEX_REASONING_EFFORT,
            writing_pad: runtime.writingPad,
            transcript_artifacts: transcriptArtifacts,
          },
          directorPlan,
          turns: trace.turns,
          metrics: trace.metrics,
          writingPadSnapshots: trace.writingPadSnapshots,
          quality_status: hasBlockingQualityWarnings(qualityWarnings) ? 'review_before_scoring' : 'ok',
          quality_warnings: qualityWarnings,
        },
        null,
        2,
      ),
      'utf8',
    );

    keyItems[d._tid] = keyItemFor(d, nTutor, nLearner, qualityWarnings);
    console.log(`    → ${nTutor} tutor / ${nLearner} learner turns · ${((Date.now() - t0) / 1000).toFixed(0)}s`);
  }

  // Held-out key (merge with any prior key on resume so skipped dramas survive).
  let keyObj = {
    _comment:
      'HELD OUT — do not read while labelling. Joins to instrument scores + human labels only AFTER both are produced. intended_lean / intended_tutor_character / dramatic_shape are DESIGN HYPOTHESES, never labels.',
    generated: new Date().toISOString(),
    generator: args.roleMap ? 'mixed' : args.generator,
    role_map: args.roleMap || null,
    mode: args.mock
      ? 'mock'
      : args.roleMap
        ? 'real-mixed'
        : args.generator === 'codex'
          ? 'real-codex'
          : 'real-claude-code',
    model: args.mock
      ? null
      : args.roleMap
        ? `mixed (claude=${args.model}, codex=config-default@${CODEX_REASONING_EFFORT})`
        : args.generator === 'codex'
          ? `codex@${CODEX_REASONING_EFFORT}`
          : args.model,
    codex_reasoning_effort: CODEX_REASONING_EFFORT,
    writing_pad: runtime.writingPad,
    director_mode: args.directorMode,
    director_revisit_cue: args.directorRevisitPolicy !== 'none',
    director_revisit_policy: args.directorRevisitPolicy,
    director_revisit_anchor: args.directorRevisitPolicy !== 'none' ? args.directorRevisitAnchor : null,
    transcripts_dir: path.relative(WORKTREE_ROOT, args.transcriptsDir),
    seed: args.seed,
    max_turns: args.maxTurns,
    n: order.length,
    diagnostic_only:
      'diagnostic / generative read — κ on small n is noise (PHASE2-FINDINGS.md §4); the aim is ' +
      'surprising-element production judged by an external reader, NOT a human-matching classifier',
    items: {},
  };
  // Merge prior key on resume/append/targeted-regen so untouched dramas survive.
  // A clean --force run (without --only) is the one case that starts fresh.
  if (fs.existsSync(args.keyPath) && (!args.force || args.only)) {
    try {
      const prior = yaml.parse(fs.readFileSync(args.keyPath, 'utf8'));
      if (prior?.items) keyObj.items = prior.items;
    } catch (_) {
      /* start fresh */
    }
  }
  Object.assign(keyObj.items, keyItems);
  keyObj.n = Object.keys(keyObj.items).length; // total after append/merge, not just this run
  keyObj.quality_warning_count = Object.values(keyObj.items).reduce(
    (sum, item) => sum + (item.quality_warnings?.length || 0),
    0,
  );
  keyObj.quality_blocking_warning_count = Object.values(keyObj.items).reduce(
    (sum, item) => sum + (hasBlockingQualityWarnings(item.quality_warnings || []) ? 1 : 0),
    0,
  );
  fs.writeFileSync(args.keyPath, yaml.stringify(keyObj), 'utf8');

  console.log(`\nwrote transcripts → ${path.relative(WORKTREE_ROOT, args.outDir)}`);
  console.log(`wrote held-out deliberation → ${path.relative(WORKTREE_ROOT, args.delibDir)}`);
  console.log(`wrote held-out role transcripts → ${path.relative(WORKTREE_ROOT, args.transcriptsDir)}`);
  console.log(`wrote held-out key → ${path.relative(WORKTREE_ROOT, args.keyPath)}`);
  if (warnings.length) {
    console.log('\n⚠ warnings:');
    for (const w of warnings) console.log(`  - ${w}`);
  }
  const rel = path.relative(WORKTREE_ROOT, args.outDir);
  const keyRel = path.relative(WORKTREE_ROOT, args.keyPath);
  if (args.roleMap) {
    // Mixed authorship has no single arms-length critic: whichever model authored
    // ANY role can't be a clean generator≠critic judge of the whole transcript.
    // Exact backend set = whatever each of the 5 roles actually resolves to.
    const backends = new Set(ROLE_NAMES.map((r) => resolveBackend(r, args.roleMap, args.generator)));
    const both = backends.has('claude') && backends.has('codex');
    console.log(
      `\nnext (MIXED authorship — generator≠critic does NOT hold cleanly: ${[...backends].join('+')} each authored ≥1 role):\n` +
        (both
          ? `  no fully arms-length automated critic exists for a claude+codex drama; choose the critic deliberately\n` +
            `  (e.g. an OpenRouter model neither side used: --model gpt), and lean on the human labeller as primary:\n`
          : `  judge with the model that authored NO role here:\n`) +
        `  node scripts/score-poetics-phase2.js --model <critic> --sample-dir ${rel} --key ${keyRel} --out exports/poetics-phase2-mixed-<critic>.json\n` +
        `  node scripts/label-poetics-phase2.js --sample-dir ${rel} --labeller liam   # human triangulation (not a gate)`,
    );
    return;
  }
  const critic = args.generator === 'codex' ? 'gpt' : 'codex';
  const criticNote =
    args.generator === 'codex'
      ? 'non-Codex OpenRouter critic; use --model google/gemini-3.5-flash or another full model id if preferred'
      : 'Codex critic';
  console.log(
    `\nnext (generative read — generator≠critic, so this ${args.generator}-authored set is judged by ${critic}; ${criticNote}):\n` +
      `  node scripts/score-poetics-phase2.js --model ${critic} --sample-dir ${rel} --key ${keyRel} ` +
      `--out exports/poetics-phase2-${args.generator}gen-${critic}.json\n` +
      `  node scripts/label-poetics-phase2.js --sample-dir ${rel} --labeller liam   # human triangulation, in due course (not a gate)`,
  );
}

if (path.resolve(process.argv[1] || '') === __filename) {
  main().catch((e) => {
    console.error(e?.stack || String(e));
    process.exit(1);
  });
}

export {
  qualityWarningsFor,
  reframeComplianceFailures,
  reframeMatchStats,
  revoiceComplianceFailures,
  revoiceMatchStats,
};
